/**
 * Parses a URL query string literal into an object type at compile time.
 * 
 * @param S The query string literal (e.g., "a=1&b=2").
 */
export type ParseQuery<S extends string> = 
    // Base Case: If the input is empty, return an empty object.
    S extends "" ? {} : 
    // Recursive Step: Process the first segment and recurse on the rest.
    (
        // 1. Extract the key/value pair from the start of S (the first segment).
        // We assume the format is always K=V, so we extract KKey and V.
        S extends `${infer KKey}${"="|""}${infer V}` ? { [K in KKey]: V } : {}
    ) & 
    // 2. Recursively parse the remainder of the string (after the first '&').
    (
        // Find the index of the first '&'. If found, slice and recurse.
        S extends `${infer Prefix}${&${infer Remainder}>` ? ParseQuery<Remainder> : {}
    );

/**
 * Helper type to extract a key from a segment "key=value".
 * This is necessary because we cannot use the string literal itself as a mapped type key directly 
 * if it contains non-identifier characters like '='. We must infer the key name and value separately.
 */
type ExtractKeyAndValue<S extends string> = S extends `${infer KKey}${"="|""}${infer V}` ? { [K]: V } : {};

/**
 * Helper type to recursively process segments separated by '&'.
 * This simulates splitting the string into an array of segments and mapping over them.
 */
type ProcessSegments<S extends string> = 
    // Base Case: If no '&' is found, this segment is the last one.
    S extends `${infer KKey}${"="|""}${infer V}` ? ExtractKeyAndValue<S> : {} &
    // Recursive Step: Find the first segment (KKey=V) and recurse on the remainder after '&'.
    S extends `${infer Prefix}${&${infer Remainder}>` 
        ? ProcessSegments<Remainder> & ExtractKeyAndValue<Prefix>
        : {};

/**
 * Public facing type alias that uses the recursive processing logic.
 * This structure ensures correct handling of delimiters and merging object types.
 */
export type ParseQueryFinal<S extends string> = S extends "" ? {} : ProcessSegments<S>;


