/**
 * A strongly typed event emitter that ensures compile-time checks for event names 
 * and argument signatures based on the provided TEvents map.
 * 
 * @template TEvents The map defining all available events and their expected argument arrays.
 */
export class EventEmitter<TEvents extends Record<string, unknown[]>> {
    // Internal storage: Maps event name (string) to an array of handlers.
    // We use a Map internally for runtime flexibility, but the type system must enforce safety.
    private readonly handlers = new Map<string, Array<(args: any[]) => void>>();

    /**
     * Registers a handler function for a specific event name.
     * 
     * @template K The key of TEvents (the event name).
     * @param {K} name The name of the event. Must exist in TEvents.
     * @param {(...args: TEvents[K]) => void} handler The function to execute when the event is emitted.
     */
    public on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
        const nameStr = String(name);

        if (!this.handlers.has(nameStr)) {
            // Initialize the array of handlers for this new event
            this.handlers.set(nameStr, []);
        }

        // We must cast the handler to (args: any[]) => void here because 
        // TypeScript cannot guarantee that all functions stored in a heterogeneous array 
        // will have the exact same signature at runtime without complex type assertions.
        // However, by enforcing the generic constraint K on this method call, we ensure 
        // compile-time safety for the caller.
        (this.handlers.get(nameStr) as Array<(args: any[]) => void>).push((...args) => handler(...args));
    }

    /**
     * Emits an event, invoking all registered handlers in registration order.
     * 
     * @template K The key of TEvents (the event name).
     * @param {K} name The name of the event to emit. Must exist in TEvents.
     * @param {...TEvents[K]} args Arguments passed to the handlers.
     */
    public emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
        const nameStr = String(name);

        if (!this.handlers.has(nameStr)) {
            // If no one has registered for this event, do nothing.
            return;
        }

        const handlersList = this.handlers.get(nameStr)!;

        for (const handler of handlersList) {
            // The runtime call uses the provided arguments array 'args'.
            // Since we stored wrappers that execute the original handler with spread args, 
            // calling it here correctly passes all arguments.
            handler(...args);
        }
    }
